package resource

import "testing"

// @ai:generated by=claude-opus-4-8 date=2026-06-15
func TestMarkAndSnapshotDelta(t *testing.T) {
	base := Snapshot()
	MarkDB()
	MarkDB()
	MarkRedis(1) // 1 op, 1 key
	MarkRedis(3) // 1 op, 3 keys（多 key 操作，如 Del/Exists）
	MarkCassandra()

	d := Snapshot().Sub(base)
	if d.DB != 2 || d.Cassandra != 1 {
		t.Errorf("delta = %+v, want DB=2 Cassandra=1", d)
	}
	if d.Redis != 2 {
		t.Errorf("Redis ops = %d, want 2", d.Redis)
	}
	if d.RedisKeys != 4 {
		t.Errorf("RedisKeys = %d, want 4 (1+3)", d.RedisKeys)
	}
	if !d.Any() {
		t.Error("Any() should be true after marking")
	}
	if !d.UsesStorage() {
		t.Error("UsesStorage() should be true")
	}
}

// @ai:generated by=claude-opus-4-8 date=2026-06-15
func TestUsesStorage_RedisCounts(t *testing.T) {
	// Redis 也計入資料儲存（依使用者要求，不再視為純快取而排除）
	if !(Stats{Redis: 1}).UsesStorage() {
		t.Error("Redis 使用應計入 UsesStorage")
	}
	if !(Stats{Cassandra: 1}).UsesStorage() {
		t.Error("Cassandra 應計入 UsesStorage")
	}
	if !(Stats{DB: 1}).UsesStorage() {
		t.Error("DB 應計入 UsesStorage")
	}
	if (Stats{}).Any() || (Stats{}).UsesStorage() {
		t.Error("zero Stats 不應為 Any/UsesStorage")
	}
}

// @ai:generated by=claude-opus-4-8 date=2026-06-15
func TestMarkRedis_ZeroKeysStillCountsOp(t *testing.T) {
	base := Snapshot()
	MarkRedis(0) // 無法得知 key（如 PING/原始 client），仍記 1 op、0 key
	d := Snapshot().Sub(base)
	if d.Redis != 1 {
		t.Errorf("Redis ops = %d, want 1", d.Redis)
	}
	if d.RedisKeys != 0 {
		t.Errorf("RedisKeys = %d, want 0", d.RedisKeys)
	}
}
